    {"slug": "pc-2006-001", "title": "In celebration of the successful opening of the Qinghai & Xizang railway, 2006", "title_zh": "\u5e86\u795d\u9752\u85cf\u94c1\u8def\u80dc\u5229\u901a\u8f66", "title_pinyin": "Qingzhu Qing-Zang tielu shengli tongche", "year": "2006, July", "theme": "China opens up (1990-2011)", "designer": "Yang Weiqiao (\u6768\u536b\u6865)", "call_number": "PC-2006-001", "collection": "Private collection", "description": "The Qinghai & Xizang railway completed the direct connection by rail between Beijing to Lhasa in Tibet. It is the most elevated railway in the world, a technological feat and a tourist attraction. Critics say it is meant to strengthen China's control over Tibet.", "image_url": "https://chineseposters.net/sites/default/files/images/pc-2006-001.jpg", "page_url": "https://chineseposters.net/gallery/pc-2006-001"},
